603	  area.appendChild(tag);
604	  input.value = '';
605	  input.focus();
606	}
607	function removeTag(btn) { btn.closest('.issue-tag').remove(); }
608	
609	/* ── 행 인라인 수정 ── */
610	function startRowEdit(btn) {
611	  const td = btn.closest('tr').querySelector('.editable-cell');
612	  const span = td.querySelector('.cell-text');
613	  if (td.querySelector('.row-edit-input')) return;
614	  const input = document.createElement('input');
615	  input.className = 'row-edit-input';
616	  input.value = span.textContent;
617	  span.style.display = 'none';
618	  td.appendChild(input);
619	  input.focus();
620	  function save() { span.textContent = input.value; span.style.display = ''; input.remove(); }
621	  input.addEventListener('blur', save);
622	  input.addEventListener('keydown', e => {
623	    if (e.key === 'Enter') input.blur();
624	    if (e.key === 'Escape') { input.remove(); span.style.display = ''; }
625	  });
626	}
627	
628	/* ── 행 삭제 + 순위 재정렬 ── */
629	function deleteRow(btn) {
630	  if (!confirm('삭제하시겠습니까?')) return;
631	  const tr = btn.closest('tr');
632	  const tbody = tr.closest('tbody');
633	  tr.remove();
634	  tbody.querySelectorAll('tr').forEach((r, i) => {
635	    const c = r.querySelector('.rank');
636	    if (c) c.textContent = i + 1;
637	  });
638	}
639	
640	/* ── 긍부정 탭 전환 ── */
641	function switchSentTab(tabEl, panelId) {
642	  const section = tabEl.closest('.section');
643	  section.querySelectorAll('.sent-tab').forEach(t => t.classList.remove('active'));
644	  section.querySelectorAll('.sent-panel').forEach(p => p.classList.remove('active'));
645	  tabEl.classList.add('active');
646	  document.getElementById(panelId).classList.add('active');
647	}
