649	/* ── 요약 인라인 편집 ── */
650	function startEdit(el) {
651	  if (el.nextElementSibling && el.nextElementSibling.classList.contains('summary-editor')) return;
652	  const h = el.getBoundingClientRect().height;
653	  const ta = document.createElement('textarea');
654	  ta.className = 'summary-editor';
655	  ta.value = el.dataset.md || '';
656	  ta.style.height = Math.max(h, 52) + 'px';
657	  el.style.display = 'none';
658	  el.parentNode.insertBefore(ta, el.nextSibling);
659	  ta.focus();
660	  ta.setSelectionRange(ta.value.length, ta.value.length);
661	  function save() {
662	    el.dataset.md = ta.value;
663	    el.innerHTML = marked.parse(ta.value);
664	    ta.remove();
665	    el.style.display = '';
666	  }
667	  ta.addEventListener('blur', save);
668	  ta.addEventListener('keydown', e => {
669	    if (e.key === 'Escape') { ta.removeEventListener('blur', save); ta.remove(); el.style.display = ''; }
670	  });
671	}
