  .summary-plain-text p { margin: 0 0 4px; }
  .summary-plain-text p:last-child { margin-bottom: 0; }
  .summary-plain-text ul, .summary-plain-text ol { padding-left: 16px; margin: 3px 0; }
  .summary-plain-text li { margin-bottom: 2px; }
  .summary-plain-text strong { color: #2c4a7c; font-weight: bold; }

  /* ── 긍부정 분석 ── */
  /* 종합 점수 게이지 */
  .sent-score-wrap {
    padding: 10px 14px 6px;
    display: flex; align-items: center; gap: 12px;
  }
  .sent-score-badge {
    flex-shrink: 0;
    display: flex; flex-direction: column; align-items: center;
    background: #eaf4ee; border: 1px solid #82d4a0; border-radius: 6px;
    padding: 6px 12px; min-width: 64px;
  }
  .sent-score-badge .badge-num {
    font-size: 22px; font-weight: bold; color: #1a7a3a; line-height: 1.1;
  }
  .sent-score-badge .badge-label {
    font-size: 10px; color: #555; margin-top: 2px;
  }
  .sent-gauge-box { flex: 1; }
  .sent-gauge-label {
    display: flex; justify-content: space-between;
    font-size: 10px; color: #888; margin-bottom: 3px;
  }
  .sent-gauge-track {
    height: 12px; background: #f0e0e0; border-radius: 6px;
    overflow: hidden; position: relative;
  }
  /* 중간점(0) 기준선 */
  .sent-gauge-track::after {
    content: ''; position: absolute;
    left: 50%; top: 0; height: 100%; width: 2px;
    background: #ccc;
  }
  .sent-gauge-fill {
    height: 100%; border-radius: 6px 0 0 6px;
    background: linear-gradient(to right, #27ae60, #52c97a);
    transition: width 0.6s ease;
  }
  .sent-stat-row {
    display: flex; gap: 8px; padding: 0 14px 8px;
  }
  .sent-stat-chip {
    font-size: 11px; padding: 2px 8px; border-radius: 10px;
    display: flex; align-items: center; gap: 4px;
  }
  .sent-stat-chip.pos { background: #eaf4ee; color: #1a7a3a; border: 1px solid #82d4a0; }
  .sent-stat-chip.neg { background: #feecec; color: #c0392b; border: 1px solid #f5a0a0; }
  /* 탭 */
  .sent-tabs {
    display: flex; gap: 3px; padding: 4px 8px 0;
    background: #f7f9fc;
    border-top: 1px solid #e8eaf0;
    border-bottom: 1px solid #d0d5de;
    flex-shrink: 0;
  }
  .sent-tab {
    padding: 3px 10px; border: 1px solid #ccc; border-bottom: none;
    border-radius: 3px 3px 0 0; background: #e8edf5; cursor: pointer;
    font-size: 12px; color: #555;
  }
  .sent-tab.active {
    background: #fff; border-color: #2c4a7c; color: #2c4a7c;
    font-weight: bold; border-bottom: 1px solid #fff; margin-bottom: -1px;
  }
  .sent-panel { display: none; }
  .sent-panel.active { display: block; }
  .kw-table { width: 100%; border-collapse: collapse; font-size: 12px; }
  .kw-table th {
    background: #f5f7fb; color: #555; font-weight: bold;
    text-align: center; padding: 4px 4px;
    border-bottom: 1px solid #e0e3eb; white-space: nowrap;
  }
  .kw-table th.col-rank { width: 1%; min-width: 26px; }
  .kw-table td { padding: 4px 8px; border-bottom: 1px solid #eef0f5; text-align: center; color: #333; }
  .kw-table td.rank { color: #e05a2b; font-weight: bold; padding: 4px 4px; }
  .kw-table td.kw-word { color: #2c4a7c; }
  .kw-table tr:last-child td { border-bottom: none; }

  /* ── 상담 평가 ── */
  .eval-body {
    flex: 1; display: flex; flex-direction: column; min-height: 0; overflow-y: auto; padding: 8px 10px;
  }
  /* 레이더 + 항목 레이아웃 */
  .radar-layout {
    display: flex; gap: 12px; align-items: flex-start;
  }
  .radar-canvas-box { flex-shrink: 0; width: 185px; height: 185px; }
  .radar-legend-box { flex: 1; display: flex; flex-direction: column; gap: 0; }
  /* 지표 카드 */
  .radar-item {
    padding: 5px 6px;
    border-bottom: 1px solid #f0f2f8;
    display: flex; flex-direction: column; gap: 2px;
  }
  .radar-item:last-child { border-bottom: none; }
  .radar-item-header {
    display: flex; align-items: center; justify-content: space-between;
  }
  .r-label { font-size: 11.5px; font-weight: bold; color: #2c4a7c; }
  .r-score-badge {
    font-size: 10px; font-weight: bold;
    padding: 1px 6px; border-radius: 8px;
    background: #edf2fb; color: #2c4a7c; border: 1px solid #c0cfec;
  }
  .r-score-bar {
    height: 4px; background: #e8edf5; border-radius: 2px; overflow: hidden; margin: 2px 0;
  }
  .r-score-fill {
    height: 100%; border-radius: 2px;
    background: linear-gradient(to right, #2c4a7c, #5b8def);
    transition: width 0.5s ease;
  }
  .r-desc { font-size: 10.5px; color: #666; line-height: 1.45; }

  /* 총점 요약 */
  .eval-total-row {
    display: flex; align-items: center; justify-content: flex-end; gap: 8px;
    padding: 6px 0 2px;
    border-top: 1px solid #e0e3eb;
    margin-top: 6px;
  }
  .eval-total-label { font-size: 11px; color: #666; }
  .eval-total-score { font-size: 16px; font-weight: bold; color: #2c4a7c; }
  .eval-total-max { font-size: 11px; color: #aaa; }
  .eval-grade {
    font-size: 11px; font-weight: bold; padding: 2px 8px; border-radius: 10px;
    background: #eaf4ee; color: #1a7a3a; border: 1px solid #82d4a0;
  }

  /* ── 푸터 ── */
  .popup-footer {
    display: flex; justify-content: center; gap: 8px;
    padding: 8px 14px 12px; flex-shrink: 0;
    border-top: 1px solid #e8eaf0;
  }
  .btn-confirm {
    padding: 6px 36px; background: #6b7280; color: #fff;
    border: none; border-radius: 4px; font-size: 13px; font-weight: bold; cursor: pointer;
  }
  .btn-confirm:hover { background: #4b5563; }
  .btn-send {
    padding: 6px 36px; background: #2c4a7c; color: #fff;
    border: none; border-radius: 4px; font-size: 13px; font-weight: bold; cursor: pointer;
  }
  .btn-send:hover { background: #1e3460; }
</style>
