<script>
/* ── 이슈 태그 ── */
function addIssueTag() {
  const input = document.getElementById('issueInput');
  const val = input.value.trim();
  if (!val) return;
  const area = document.getElementById('issueTagArea');
  const tag = document.createElement('span');
  tag.className = 'issue-tag user';
  tag.innerHTML = val + ' <button class="del-btn" onclick="removeTag(this)">×</button>';
  area.appendChild(tag);
  input.value = '';
  input.focus();
}
function removeTag(btn) { btn.closest('.issue-tag').remove(); }

/* ── 행 인라인 수정 ── */
function startRowEdit(btn) {
  const td = btn.closest('tr').querySelector('.editable-cell');
  const span = td.querySelector('.cell-text');
  if (td.querySelector('.row-edit-input')) return;
  const input = document.createElement('input');
  input.className = 'row-edit-input';
  input.value = span.textContent;
  span.style.display = 'none';
  td.appendChild(input);
  input.focus();
  function save() { span.textContent = input.value; span.style.display = ''; input.remove(); }
  input.addEventListener('blur', save);
  input.addEventListener('keydown', e => {
    if (e.key === 'Enter') input.blur();
    if (e.key === 'Escape') { input.remove(); span.style.display = ''; }
  });
}

/* ── 행 삭제 + 순위 재정렬 ── */
function deleteRow(btn) {
  if (!confirm('삭제하시겠습니까?')) return;
  const tr = btn.closest('tr');
  const tbody = tr.closest('tbody');
  tr.remove();
  tbody.querySelectorAll('tr').forEach((r, i) => {
    const c = r.querySelector('.rank');
    if (c) c.textContent = i + 1;
  });
}

/* ── 긍부정 탭 전환 ── */
function switchSentTab(tabEl, panelId) {
  const section = tabEl.closest('.section');
  section.querySelectorAll('.sent-tab').forEach(t => t.classList.remove('active'));
  section.querySelectorAll('.sent-panel').forEach(p => p.classList.remove('active'));
  tabEl.classList.add('active');
  document.getElementById(panelId).classList.add('active');
}

/* ── 요약 인라인 편집 ── */
function startEdit(el) {
  if (el.nextElementSibling && el.nextElementSibling.classList.contains('summary-editor')) return;
  const h = el.getBoundingClientRect().height;
  const ta = document.createElement('textarea');
  ta.className = 'summary-editor';
  ta.value = el.dataset.md || '';
  ta.style.height = Math.max(h, 52) + 'px';
  el.style.display = 'none';
  el.parentNode.insertBefore(ta, el.nextSibling);
  ta.focus();
  ta.setSelectionRange(ta.value.length, ta.value.length);
  function save() {
    el.dataset.md = ta.value;
    el.innerHTML = marked.parse(ta.value);
    ta.remove();
    el.style.display = '';
  }
  ta.addEventListener('blur', save);
  ta.addEventListener('keydown', e => {
    if (e.key === 'Escape') { ta.removeEventListener('blur', save); ta.remove(); el.style.display = ''; }
  });
}

/* ── DOMContentLoaded 초기화 ── */
document.addEventListener('DOMContentLoaded', () => {

  /* 마크다운 렌더링 */
  document.querySelectorAll('.summary-plain-text[data-md]').forEach(el => {
    el.innerHTML = marked.parse(el.dataset.md);
  });

