606	/* ── 이슈 태그 ── */
607	function addIssueTag() {
608	  const input = document.getElementById('issueInput');
609	  const val = input.value.trim();
610	  if (!val) return;
611	  const area = document.getElementById('issueTagArea');
612	  const tag = document.createElement('span');
613	  tag.className = 'issue-tag user';
614	  tag.innerHTML = val + ' <button class="del-btn" onclick="removeTag(this)">×</button>';
615	  area.appendChild(tag);
616	  input.value = '';
617	  input.focus();
618	}
619	function removeTag(btn) { btn.closest('.issue-tag').remove(); }
620	
621	/* ── 행 인라인 수정 ── */
622	function startRowEdit(btn) {
623	  const td = btn.closest('tr').querySelector('.editable-cell');
624	  const span = td.querySelector('.cell-text');
625	  if (td.querySelector('.row-edit-input')) return;
626	  const input = document.createElement('input');
627	  input.className = 'row-edit-input';
628	  input.value = span.textContent;
629	  span.style.display = 'none';
630	  td.appendChild(input);
631	  input.focus();
632	  function save() { span.textContent = input.value; span.style.display = ''; input.remove(); }
633	  input.addEventListener('blur', save);
634	  input.addEventListener('keydown', e => {
635	    if (e.key === 'Enter') input.blur();
636	    if (e.key === 'Escape') { input.remove(); span.style.display = ''; }
637	  });
638	}
639	
640	/* ── 행 삭제 + 순위 재정렬 ── */
641	function deleteRow(btn) {
642	  if (!confirm('삭제하시겠습니까?')) return;
643	  const tr = btn.closest('tr');
644	  const tbody = tr.closest('tbody');
645	  tr.remove();
646	  tbody.querySelectorAll('tr').forEach((r, i) => {
647	    const c = r.querySelector('.rank');
648	    if (c) c.textContent = i + 1;
649	  });
650	}
651	
