/* 긍부정 게이지 애니메이션 (부정/긍정 분리) */
const score = 66.7;
let negPct = 0;
let posPct = 0;

if (score < 0) {
  // 부정: -100 ~ 0
  negPct = Math.abs(score) / 100 * 50;
  posPct = 0;
} else if (score > 0) {
  // 긍정: 0 ~ +100
  negPct = 0;
  posPct = score / 100 * 50;
}

setTimeout(() => {
  document.getElementById('sentGaugeFillNeg').style.width = negPct + '%';
  document.getElementById('sentGaugeFillPos').style.width = posPct + '%';
}, 200);

