593	/* ── 행 인라인 수정 ── */
594	function startRowEdit(btn) {
595	  const td = btn.closest('tr').querySelector('.editable-cell');
596	  const span = td.querySelector('.cell-text');
597	  if (td.querySelector('.row-edit-input')) return;
598	  const input = document.createElement('input');
599	  input.className = 'row-edit-input';
600	  input.value = span.textContent;
601	  span.style.display = 'none';
602	  td.appendChild(input);
603	  input.focus();
604	  function save() { span.textContent = input.value; span.style.display = ''; input.remove(); }
605	  input.addEventListener('blur', save);
606	  input.addEventListener('keydown', e => {
607	    if (e.key === 'Enter') input.blur();
608	    if (e.key === 'Escape') { input.remove(); span.style.display = ''; }
609	  });
610	}
