612	/* ── 행 삭제 + 순위 재정렬 ── */
613	function deleteRow(btn) {
614	  if (!confirm('삭제하시겠습니까?')) return;
615	  const tr = btn.closest('tr');
616	  const tbody = tr.closest('tbody');
617	  tr.remove();
618	  tbody.querySelectorAll('tr').forEach((r, i) => {
619	    const c = r.querySelector('.rank');
620	    if (c) c.textContent = i + 1;
621	  });
622	}
