633	/* ── 요약 인라인 편집 ── */
634	function startEdit(el) {
635	  if (el.nextElementSibling && el.nextElementSibling.classList.contains('summary-editor')) return;
636	  const h = el.getBoundingClientRect().height;
637	  const ta = document.createElement('textarea');
638	  ta.className = 'summary-editor';
639	  ta.value = el.dataset.md || '';
640	  ta.style.height = Math.max(h, 52) + 'px';
641	  el.style.display = 'none';
642	  el.parentNode.insertBefore(ta, el.nextSibling);
643	  ta.focus();
644	  ta.setSelectionRange(ta.value.length, ta.value.length);
645	  function save() {
646	    el.dataset.md = ta.value;
647	    el.innerHTML = marked.parse(ta.value);
648	    ta.remove();
649	    el.style.display = '';
650	  }
651	  ta.addEventListener('blur', save);
652	  ta.addEventListener('keydown', e => {
653	    if (e.key === 'Escape') { ta.removeEventListener('blur', save); ta.remove(); el.style.display = ''; }
654	  });
655	}
