  font-size: 12.5px; outline: none;
}

/* ── 이슈 태그 ── */
.issue-tag-area {
  padding: 8px 10px; min-height: 40px;
  display: flex; flex-wrap: wrap; gap: 5px; align-items: center;
}
.issue-legend { width: 100%; display: flex; gap: 12px; padding: 4px 10px 0; font-size: 11px; color: #888; }
.issue-legend span { display: flex; align-items: center; gap: 4px; }
.legend-dot { width: 9px; height: 9px; border-radius: 50%; display: inline-block; }
.legend-dot.sys  { background: #5b8def; }
.legend-dot.user { background: #27ae60; }
.issue-tag {
  border-radius: 12px; padding: 3px 8px 3px 10px;
  font-size: 12px; display: inline-flex; align-items: center; gap: 4px; font-weight: 500;
}
.issue-tag.sys  { background: #e8f0fe; border: 1px solid #aac4f5; color: #1a55c4; }
.issue-tag.user { background: #e6f7ee; border: 1px solid #82d4a0; color: #1a7a3a; }
.issue-tag .del-btn { cursor: pointer; font-size: 14px; line-height: 1; background: none; border: none; padding: 0 1px; }
.issue-tag.sys  .del-btn { color: #7ba7e8; }
.issue-tag.user .del-btn { color: #6ec48b; }
.issue-tag.sys  .del-btn:hover { color: #c0392b; }
.issue-tag.user .del-btn:hover { color: #c0392b; }
.issue-input-row {
  display: flex; gap: 5px; padding: 5px 10px 7px;
  border-top: 1px solid #eef0f5;
}
.issue-input-row input {
  flex: 1; padding: 3px 8px; border: 1px solid #ccc; border-radius: 3px; font-size: 12px; outline: none;
}
.issue-input-row input:focus { border-color: #2c4a7c; }
.issue-input-row button {
  padding: 3px 10px; background: #2c4a7c; color: #fff; border: none; border-radius: 3px; font-size: 12px; cursor: pointer;
}
.issue-input-row button:hover { background: #1e3460; }

