/* ── 섹션 공통 ── */
.section {
  border: 1px solid #d0d5de;
  border-radius: 4px;
  overflow: hidden;
  flex-shrink: 0;
}
.col-left  .section:last-child,
.col-right .section:last-child {
  flex: 1; display: flex; flex-direction: column; min-height: 0;
}
.col-left  .section:last-child .section-inner,
.col-right .section:last-child .section-inner {
  flex: 1; overflow-y: auto; min-height: 0;
}
.col-right .section:nth-child(2) {
  display: flex; flex-direction: column;
  max-height: 145px;
  overflow-y: auto;
}
.col-right .section:nth-child(3) {
  display: flex; flex-direction: column;
  max-height: 220px;
  overflow-y: auto;
}
.col-right .section:nth-child(3) .section-inner,
.col-right .section:nth-child(3) .eval-body {
  flex: 1; overflow-y: auto; min-height: 0;
}
.section-title {
  background: #f0f3f8;
  border-bottom: 1px solid #d0d5de;
  padding: 5px 10px;
  font-weight: bold; font-size: 12px; color: #333;
  flex-shrink: 0;
}
.section-inner { display: flex; flex-direction: column; }

/* ── 고객 기본정보 ── */
.customer-inline {
  display: flex; align-items: center; gap: 8px;
  flex-wrap: wrap; padding: 6px 10px;
}
.customer-inline .name { font-weight: bold; font-size: 14px; color: #2c4a7c; }
.customer-inline .divider { color: #bbb; }
.customer-inline .info-chip {
  background: #f0f3f8; border: 1px solid #d0d5de;
  border-radius: 3px; padding: 2px 7px; font-size: 12px; color: #444;
}
.customer-inline .info-label { font-size: 11px; color: #888; margin-right: 3px; }

/* ── 공통 테이블 ── */
.data-table { width: 100%; border-collapse: collapse; font-size: 12.5px; }
.data-table thead th {
  background: #f5f7fb; color: #666; font-weight: bold;
  font-size: 10.5px;
  text-align: center; padding: 3px 4px;
  border-bottom: 1px solid #e0e3eb; white-space: nowrap;
}
.data-table thead th.col-rank { width: 1%; min-width: 26px; }
.data-table tbody td { padding: 5px 8px; border-bottom: 1px solid #eef0f5; color: #333; }
.data-table tbody tr:last-child td { border-bottom: none; }
.data-table tbody td.rank {
  text-align: center; color: #e05a2b; font-weight: bold;
  padding: 5px 4px; white-space: nowrap;
}

/* ── 인라인 편집 ── */
.action-cell { text-align: center; white-space: nowrap; padding: 3px 4px; }
.icon-btn { background: none; border: none; cursor: pointer; font-size: 13px; padding: 2px 3px; border-radius: 2px; }
.edit-btn { color: #2c4a7c; }
.edit-btn:hover { background: #e8f0fe; }
.del-row-btn { color: #c0392b; }
.del-row-btn:hover { background: #ffe5e3; }
.row-edit-input {
  width: 100%; padding: 2px 6px;
  border: 1px solid #2c4a7c; border-radius: 3px;
  font-size: 12.5px; outline: none;
}

/* ── 이슈 태그 ── */
.issue-tag-area {
  padding: 8px 10px; min-height: 40px;
  display: flex; flex-wrap: wrap; gap: 5px; align-items: center;
}
.issue-legend { width: 100%; display: flex; gap: 12px; padding: 4px 10px 0; font-size: 11px; color: #888; }
.issue-legend span { display: flex; align-items: center; gap: 4px; }
.legend-dot { width: 9px; height: 9px; border-radius: 50%; display: inline-block; }
.legend-dot.sys  { background: #5b8def; }
.legend-dot.user { background: #27ae60; }
.issue-tag {
  border-radius: 12px; padding: 3px 8px 3px 10px;
  font-size: 12px; display: inline-flex; align-items: center; gap: 4px; font-weight: 500;
}
.issue-tag.sys  { background: #e8f0fe; border: 1px solid #aac4f5; color: #1a55c4; }
.issue-tag.user { background: #e6f7ee; border: 1px solid #82d4a0; color: #1a7a3a; }
.issue-tag .del-btn { cursor: pointer; font-size: 14px; line-height: 1; background: none; border: none; padding: 0 1px; }
.issue-tag.sys  .del-btn { color: #7ba7e8; }
.issue-tag.user .del-btn { color: #6ec48b; }
.issue-tag.sys  .del-btn:hover { color: #c0392b; }
.issue-tag.user .del-btn:hover { color: #c0392b; }
.issue-input-row {
  display: flex; gap: 5px; padding: 5px 10px 7px;
  border-top: 1px solid #eef0f5;
}
.issue-input-row input {
  flex: 1; padding: 3px 8px; border: 1px solid #ccc; border-radius: 3px; font-size: 12px; outline: none;
}
.issue-input-row input:focus { border-color: #2c4a7c; }
.issue-input-row button {
  padding: 3px 10px; background: #2c4a7c; color: #fff; border: none; border-radius: 3px; font-size: 12px; cursor: pointer;
}
.issue-input-row button:hover { background: #1e3460; }

/* ── 상담요약 ── */
.summary-plain-item { padding: 7px 10px; border-bottom: 1px solid #eef0f5; }
.summary-plain-item:last-child { border-bottom: none; }
.summary-plain-label { font-size: 11px; font-weight: bold; color: #888; margin-bottom: 3px; }
.summary-plain-text {
  font-size: 12.5px; color: #333; line-height: 1.6;
  cursor: text; padding: 3px 4px; border-radius: 3px; transition: background 0.15s;
}
.summary-plain-text:hover { background: #f5f7fb; }
.summary-editor {
  display: block; width: 100%; padding: 6px 12px;
  font-size: 12px; line-height: 1.6;
  font-family: '맑은 고딕', 'Malgun Gothic', monospace;
  background: #fffdf0; border: 2px solid #f0c040; border-left: none; border-right: none;
  outline: none; resize: none; overflow-y: auto; color: #333; box-sizing: border-box;
}
.summary-plain-text p { margin: 0 0 4px; }
.summary-plain-text p:last-child { margin-bottom: 0; }
.summary-plain-text ul, .summary-plain-text ol { padding-left: 16px; margin: 3px 0; }
.summary-plain-text li { margin-bottom: 2px; }
.summary-plain-text strong { color: #2c4a7c; font-weight: bold; }

