file.content:
.sent-gauge-track {
  height: 12px; background: #e8edf5; border-radius: 6px;
  overflow: hidden; position: relative;
}
/* 중간점(0) 기준선 */
.sent-gauge-track::after {
  content: ''; position: absolute;
  left: 50%; top: 0; height: 100%; width: 2px;
  background: #ccc;
}
.sent-gauge-fill {
  height: 100%;
  background: linear-gradient(to right, #27ae60, #52c97a);
  transition: width 0.6s ease;
  position: relative;
}
.sent-gauge-fill.negative {
  background: #c0392b;
  border-radius: 6px 0 0 6px;
}
.sent-gauge-fill.positive {
  background: linear-gradient(to right, #27ae60, #52c97a);
  border-radius: 0 6px 6px 0;
}
/* 긍부정 현황 - 좌우 배치 (가로 막대 형식) */
.sent-items-container {
  padding: 12px 14px 10px;
  display: flex; flex-direction: column; gap: 10px;
  flex: 1; min-height: 0;
}
.sent-bar-row {
  display: flex; align-items: stretch; gap: 0; flex: 1; min-height: 0;
}
.sent-items-left {
  flex: 1; display: flex; flex-direction: column; gap: 0;
  background: #fef8f8;
}
.sent-items-right {
  flex: 1; display: flex; flex-direction: column; gap: 0;
  background: #f8fef8;
}
.sent-item {
  flex: 1; display: flex; align-items: center;
  font-size: 12px; padding: 6px 8px; border-bottom: 1px solid #eef0f5;
  color: #333;
}
.sent-item:last-child {
  border-bottom: none;
}
.sent-item-label {
  color: #333; line-height: 1.4;
}
.sent-items-left .sent-item {
  text-align: right; justify-content: flex-end;
}
.sent-items-right .sent-item {
  text-align: left; justify-content: flex-start;
}

/* ── 상담 평가 ── */
.eval-body {
  flex: 1; display: flex; flex-direction: column; min-height: 0; overflow-y: auto; padding: 8px 10px;
}
/* 레이더 + 항목 레이아웃 */
.radar-layout {
  display: flex; gap: 12px; align-items: flex-start;
}
.radar-canvas-box { flex-shrink: 0; width: 185px; height: 185px; }
.radar-legend-box { flex: 1; display: flex; flex-direction: column; gap: 0; }
/* 지표 카드 */
.radar-item {
  padding: 5px 6px;
  border-bottom: 1px solid #f0f2f8;
  display: flex; flex-direction: column; gap: 2px;
}
.radar-item:last-child { border-bottom: none; }
.radar-item-header {
  display: flex; align-items: center; justify-content: space-between;
}
.r-label { font-size: 11.5px; font-weight: bold; color: #2c4a7c; }
.r-score-badge {
  font-size: 10px; font-weight: bold;
  padding: 1px 6px; border-radius: 8px;
  background: #edf2fb; color: #2c4a7c; border: 1px solid #c0cfec;
}
.r-score-bar {
  height: 4px; background: #e8edf5; border-radius: 2px; overflow: hidden; margin: 2px 0;
}
.r-score-fill {
  height: 100%; border-radius: 2px;
  background: linear-gradient(to right, #2c4a7c, #5b8def);
  transition: width 0.5s ease;
}
.r-desc { font-size: 10.5px; color: #666; line-height: 1.45; }

/* 총점 요약 */
.eval-total-row {
  display: flex; align-items: center; justify-content: flex-end; gap: 8px;
  padding: 6px 0 2px;
  border-top: 1px solid #e0e3eb;

